   174→    let normal = Normal::new(0.0, 1.0)?;
   175→    
   176→    // True coefficients - only first n_true are non-zero
   177→    let mut true_coefs = Array1::zeros(n_features + 1); // +1 for intercept
   178→    true_coefs[0] = 2.0; // intercept
   179→    for i in 1..=n_true {
   180→        true_coefs[i] = rng.gen_range(-3.0..3.0);
   181→    }
   182→    
   183→    // Generate training data
   184→    let mut x_train = Array2::zeros((n_obs, n_features + 1));
   185→    x_train.column_mut(0).fill(1.0); // intercept
   186→    for i in 0..n_obs {
   187→        for j in 1..=n_features {
   188→            x_train[[i, j]] = normal.sample(&mut rng);
   189→        }
   190→    }
   191→    
   192→    // Generate response with noise
