   199→    x_test.column_mut(0).fill(1.0);
   200→    for i in 0..n_test {
   201→        for j in 1..=n_features {
   202→            x_test[[i, j]] = normal.sample(&mut rng);
   203→        }
   204→    }
   205→    
   206→    let y_test = x_test.dot(&true_coefs) + 
   207→        Array1::from_iter((0..n_test).map(|_| normal.sample(&mut rng) * 0.5));
   208→    
   209→    Ok((x_train, y_train, x_test, y_test, true_coefs))
   210→}
